#include<bits/stdc++.h>
using namespace std;
int a[3001][3001];
int ans=0;
bool vis[3001][3001];
int dx[5]={1,-1,0,0,0};
int dy[5]={0,0,1,-1,0};

struct node
{
	int x,y;
};
int main()
{
	int n;
	scanf("%d",&n);
	while(n--)
	{
		int x,y;
		scanf("%d%d",&x,&y);
		x+=1000,y+=1000;
		if(!vis[x][y])
		{
			vis[x][y]=true;
			for(int i=0;i<4;i++)
			{
				int x1=x+dx[i];
				int y1=y+dy[i];
				a[x1][y1]++;
			}
			queue<node> q;
			for(int i=0;i<5;i++)
			{
				int x1=x+dx[i];
				int y1=y+dy[i];
				if(vis[x1][y1]&&a[x1][y1]==3)
				{
					q.push((node){x1,y1});
				} 
			} 
			while(!q.empty())
			{
				node t=q.front();
				q.pop();
				for(int i=0;i<4;i++)
				{
					node t1;
					t1.x=t.x+dx[i];
					t1.y=t.y+dy[i];
					if(!vis[t1.x][t1.y])
					{
						vis[t1.x][t1.y]=true;
						for(int i=0;i<4;i++)
						{
							int x1=t1.x+dx[i];
							int y1=t1.y+dy[i];
							a[x1][y1]++;
						}
						ans++;
						for(int j=0;j<5;j++)
						{
							node t2=(node){t1.x+dx[j],t1.y+dy[j]};
							if(vis[t2.x][t2.y]&&a[t2.x][t2.y]==3)
							{
								q.push(t2);
							}
						}
					}
				}
			}
		}
		else
		{
			ans--;
		}
		printf("%d\n",ans);
	}
	return 0;
}
